async function navigateToGraph(targetGraph) {
	const canvas = useCanvasStore().canvas;
	if (!canvas) return;
	if (canvas.graph !== targetGraph) {
		canvas.subgraph = targetGraph.isRootGraph ? void 0 : targetGraph;
		canvas.setGraph(targetGraph);
		await nextTick();
		await new Promise((resolve) => requestAnimationFrame(() => requestAnimationFrame(resolve)));
	}
}
function useFocusNode() {
	const canvasStore = useCanvasStore();
	async function focusNode(nodeId, executionIdMap) {
		if (!canvasStore.canvas) return;
		const parentNode = getRootParentNode(app.rootGraph, nodeId);
		if (parentNode && isGroupNode(parentNode) && parentNode.graph) {
			await navigateToGraph(parentNode.graph);
			canvasStore.canvas?.animateToBounds(parentNode.boundingRect);
			return;
		}
		const graphNode = executionIdMap ? executionIdMap.get(nodeId) : getNodeByExecutionId(app.rootGraph, nodeId);
		if (!graphNode?.graph) return;
		await navigateToGraph(graphNode.graph);
		canvasStore.canvas?.animateToBounds(graphNode.boundingRect);
	}
	async function enterSubgraph(nodeId, executionIdMap) {
		if (!canvasStore.canvas) return;
		const graphNode = executionIdMap ? executionIdMap.get(nodeId) : getNodeByExecutionId(app.rootGraph, nodeId);
		if (!graphNode?.graph) return;
		await navigateToGraph(graphNode.graph);
		useLitegraphService().fitView();
	}
	return {
		focusNode,
		enterSubgraph
	};
}
