//#region src/composables/useCopy.ts
var clipboardHTMLWrapper = ["<meta charset=\"utf-8\"><div><span data-metadata=\"", "\"></span></div><span style=\"white-space:pre-wrap;\">Text</span>"];
/**
* Adds a handler on copy that serializes selected nodes to JSON
*/
var useCopy = () => {
	const canvasStore = useCanvasStore();
	useEventListener(document, "copy", (e) => {
		if (shouldIgnoreCopyPaste(e.target)) return;
		const canvas = canvasStore.canvas;
		if (canvas?.selectedItems) {
			const serializedData = canvas.copyToClipboard();
			const base64Data = btoa(String.fromCharCode(...Array.from(new TextEncoder().encode(serializedData))));
			e.clipboardData?.setData("text/html", clipboardHTMLWrapper.join(base64Data));
			e.preventDefault();
			e.stopImmediatePropagation();
			return false;
		}
	});
};
