//#region src/platform/settings/composables/useLitegraphSettings.ts
/**
* Watch for changes in the setting store and update the LiteGraph settings accordingly.
*/
var useLitegraphSettings = () => {
	const settingStore = useSettingStore();
	const canvasStore = useCanvasStore();
	watchEffect(() => {
		const canvasInfoEnabled = settingStore.get("Comfy.Graph.CanvasInfo");
		if (canvasStore.canvas) {
			canvasStore.canvas.show_info = canvasInfoEnabled;
			canvasStore.canvas.draw(false, true);
		}
	});
	watchEffect(() => {
		const zoomSpeed = settingStore.get("Comfy.Graph.ZoomSpeed");
		if (canvasStore.canvas) canvasStore.canvas.zoom_speed = zoomSpeed;
	});
	watchEffect(() => {
		const autoPanSpeed = settingStore.get("Comfy.Graph.AutoPanSpeed");
		if (canvasStore.canvas) canvasStore.canvas.auto_pan_speed = autoPanSpeed;
	});
	watchEffect(() => {
		LiteGraph.snaps_for_comfy = settingStore.get("Comfy.Node.AutoSnapLinkToSlot");
	});
	watchEffect(() => {
		LiteGraph.snap_highlights_node = settingStore.get("Comfy.Node.SnapHighlightsNode");
	});
	watchEffect(() => {
		LGraphNode.keepAllLinksOnBypass = settingStore.get("Comfy.Node.BypassAllLinksOnDelete");
	});
	watchEffect(() => {
		LiteGraph.middle_click_slot_add_default_node = settingStore.get("Comfy.Node.MiddleClickRerouteNode");
	});
	watchEffect(() => {
		const linkRenderMode = settingStore.get("Comfy.LinkRenderMode");
		if (canvasStore.canvas) {
			canvasStore.canvas.links_render_mode = linkRenderMode;
			canvasStore.canvas.setDirty(false, true);
		}
	});
	watchEffect(() => {
		const spread = settingStore.get("Comfy.Canvas.LinkLaneSpread");
		const { canvas } = canvasStore;
		if (canvas) {
			canvas.linkLaneSpread = spread;
			canvas.setDirty(false, true);
		}
	});
	watchEffect(() => {
		const minFontSizeForLOD = settingStore.get("LiteGraph.Canvas.MinFontSizeForLOD");
		if (canvasStore.canvas) {
			canvasStore.canvas.min_font_size_for_lod = minFontSizeForLOD;
			canvasStore.canvas.setDirty(true, true);
		}
	});
	watchEffect(() => {
		const linkMarkerShape = settingStore.get("Comfy.Graph.LinkMarkers");
		const { canvas } = canvasStore;
		if (canvas) {
			canvas.linkMarkerShape = linkMarkerShape;
			canvas.setDirty(false, true);
		}
	});
	watchEffect(() => {
		const maximumFps = settingStore.get("LiteGraph.Canvas.MaximumFps");
		const { canvas } = canvasStore;
		if (canvas) canvas.maximumFps = maximumFps;
	});
	watchEffect(() => {
		const dragZoomEnabled = settingStore.get("Comfy.Graph.CtrlShiftZoom");
		const { canvas } = canvasStore;
		if (canvas) canvas.dragZoomEnabled = dragZoomEnabled;
	});
	watchEffect(() => {
		const liveSelection = settingStore.get("Comfy.Graph.LiveSelection");
		const { canvas } = canvasStore;
		if (canvas) canvas.liveSelection = liveSelection;
	});
	watchEffect(() => {
		CanvasPointer.doubleClickTime = settingStore.get("Comfy.Pointer.DoubleClickTime");
	});
	watchEffect(() => {
		CanvasPointer.bufferTime = settingStore.get("Comfy.Pointer.ClickBufferTime");
	});
	watchEffect(() => {
		CanvasPointer.maxClickDrift = settingStore.get("Comfy.Pointer.ClickDrift");
	});
	watchEffect(() => {
		LiteGraph.CANVAS_GRID_SIZE = settingStore.get("Comfy.SnapToGrid.GridSize");
	});
	watchEffect(() => {
		LiteGraph.alwaysSnapToGrid = settingStore.get("pysssss.SnapToGrid");
	});
	watchEffect(() => {
		LiteGraph.context_menu_scaling = settingStore.get("LiteGraph.ContextMenu.Scaling");
	});
	watchEffect(() => {
		LiteGraph.Reroute.maxSplineOffset = settingStore.get("LiteGraph.Reroute.SplineOffset");
	});
	watchEffect(() => {
		const navigationMode = settingStore.get("Comfy.Canvas.NavigationMode");
		LiteGraph.canvasNavigationMode = navigationMode;
		LiteGraph.macTrackpadGestures = navigationMode === "standard";
	});
	watchEffect(() => {
		LiteGraph.leftMouseClickBehavior = settingStore.get("Comfy.Canvas.LeftMouseClickBehavior");
	});
	watchEffect(() => {
		LiteGraph.mouseWheelScroll = settingStore.get("Comfy.Canvas.MouseWheelScroll");
	});
	watchEffect(() => {
		LiteGraph.saveViewportWithGraph = settingStore.get("Comfy.EnableWorkflowViewRestore");
	});
	watchEffect(() => {
		const selectChildren = settingStore.get("LiteGraph.Group.SelectChildrenOnClick");
		if (canvasStore.canvas) canvasStore.canvas.groupSelectChildren = selectChildren;
	});
};
