//#region src/platform/workflow/persistence/composables/useWorkflowAutoSave.ts
function useWorkflowAutoSave() {
	const workflowStore = useWorkflowStore();
	const settingStore = useSettingStore();
	const workflowService = useWorkflowService();
	const autoSaveSetting = computed(() => settingStore.get("Comfy.Workflow.AutoSave"));
	const autoSaveDelay = computed(() => settingStore.get("Comfy.Workflow.AutoSaveDelay"));
	let autoSaveTimeout = null;
	let isSaving = false;
	let needsAutoSave = false;
	const scheduleAutoSave = () => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		if (autoSaveSetting.value === "after delay") {
			if (isSaving) {
				needsAutoSave = true;
				return;
			}
			const delay = autoSaveDelay.value;
			autoSaveTimeout = setTimeout(async () => {
				const activeWorkflow = workflowStore.activeWorkflow;
				if (activeWorkflow?.isModified && activeWorkflow.isPersisted) try {
					isSaving = true;
					await workflowService.saveWorkflow(activeWorkflow);
				} catch (err) {
					console.error("Auto save failed:", err);
				} finally {
					isSaving = false;
					if (needsAutoSave) {
						needsAutoSave = false;
						scheduleAutoSave();
					}
				}
			}, delay);
		}
	};
	watch(autoSaveSetting, (newSetting) => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		if (newSetting === "after delay" && workflowStore.activeWorkflow?.isModified) scheduleAutoSave();
	}, { immediate: true });
	const onGraphChanged = () => {
		scheduleAutoSave();
	};
	api.addEventListener("graphChanged", onGraphChanged);
	onUnmounted(() => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		api.removeEventListener("graphChanged", onGraphChanged);
	});
}
//#endregion
//#region src/platform/workflow/persistence/base/hashUtil.ts
/**
* FNV-1a hash function for creating short, deterministic keys from strings.
*
* Used to create 8-character hex keys from workflow paths for localStorage keys.
* FNV-1a is chosen for its simplicity, speed, and good distribution properties.
*
* @param str - The string to hash (typically a workflow path)
* @returns A 32-bit unsigned integer hash
*/
function fnv1a(str) {
	let hash = 2166136261;
	for (let i = 0; i < str.length; i++) {
		hash ^= str.charCodeAt(i);
		hash = Math.imul(hash, 16777619);
	}
	return hash >>> 0;
}
/**
* Creates an 8-character hex key from a workflow path using FNV-1a hash.
*
* @param path - The workflow path (e.g., "workflows/My Workflow.json")
* @returns An 8-character hex string (e.g., "a1b2c3d4")
*
* @example
* hashPath("workflows/Untitled.json") // "1a2b3c4d"
*/
function hashPath(path) {
	return fnv1a(path).toString(16).padStart(8, "0");
}
//#endregion
//#region src/platform/workflow/persistence/base/storageKeys.ts
/**
* Gets the current workspace ID from sessionStorage.
* Returns 'personal' for personal workspace or when no workspace is set.
*
* NOTE: This is called fresh each time rather than cached at module load,
* because the workspace auth store may not have set sessionStorage yet
* when this module is first imported.
*/
function getWorkspaceId() {
	try {
		const json = sessionStorage.getItem(WORKSPACE_STORAGE_KEYS.CURRENT_WORKSPACE);
		if (!json) return "personal";
		const workspace = JSON.parse(json);
		if (workspace.type === "personal" || !workspace.id) return "personal";
		return workspace.id;
	} catch {
		return "personal";
	}
}
/**
* Storage key generators for V2 workflow persistence.
*
* localStorage keys are scoped by workspaceId.
* sessionStorage keys are scoped by clientId.
*/
var StorageKeys = {
	draftIndex(workspaceId) {
		return `Comfy.Workflow.DraftIndex.v2:${workspaceId}`;
	},
	draftPayload(path, workspaceId) {
		return `Comfy.Workflow.Draft.v2:${workspaceId}:${hashPath(path)}`;
	},
	draftKey(path) {
		return hashPath(path);
	},
	activePath(clientId) {
		return `Comfy.Workflow.ActivePath:${clientId}`;
	},
	openPaths(clientId) {
		return `Comfy.Workflow.OpenPaths:${clientId}`;
	},
	lastActivePath(workspaceId) {
		return `Comfy.Workflow.LastActivePath:${workspaceId}`;
	},
	lastOpenPaths(workspaceId) {
		return `Comfy.Workflow.LastOpenPaths:${workspaceId}`;
	},
	prefixes: {
		draftIndex: "Comfy.Workflow.DraftIndex.v2:",
		draftPayload: "Comfy.Workflow.Draft.v2:",
		activePath: "Comfy.Workflow.ActivePath:",
		openPaths: "Comfy.Workflow.OpenPaths:",
		lastActivePath: "Comfy.Workflow.LastActivePath:",
		lastOpenPaths: "Comfy.Workflow.LastOpenPaths:"
	}
};
