/**
* Composable for loading templates from URL query parameters
*
* Supports URLs like:
* - /?template=flux_simple (loads with default source)
* - /?template=flux_simple&source=custom (loads from custom source)
* - /?template=flux_simple&mode=linear (loads template in linear mode)
*
* Input validation:
* - Template, source, and mode parameters must match: ^[a-zA-Z0-9_-]+$
* - Invalid formats are rejected with console warnings
*/
function useTemplateUrlLoader() {
	const route = useRoute();
	const router = useRouter();
	const { t } = useI18n();
	const toast = useToast();
	const templateWorkflows = useTemplateWorkflows();
	const canvasStore = useCanvasStore();
	const TEMPLATE_NAMESPACE = PRESERVED_QUERY_NAMESPACES.TEMPLATE;
	const SUPPORTED_MODES = ["linear"];
	/**
	* Validates parameter format to prevent path traversal and injection attacks
	* Allows: letters, numbers, underscores, hyphens, and dots (for version numbers)
	* Blocks: path separators (/, \), special chars that could enable injection
	*/
	const isValidParameter = (param) => {
		return /^[a-zA-Z0-9_.-]+$/.test(param);
	};
	/**
	* Type guard to check if a value is a supported mode
	*/
	const isSupportedMode = (mode) => {
		return SUPPORTED_MODES.includes(mode);
	};
	/**
	* Removes template, source, and mode parameters from URL
	*/
	const cleanupUrlParams = () => {
		const newQuery = { ...route.query };
		delete newQuery.template;
		delete newQuery.source;
		delete newQuery.mode;
		router.replace({ query: newQuery });
	};
	/**
	* Loads template from URL query parameters if present
	* Handles errors internally and shows appropriate user feedback
	*/
	const loadTemplateFromUrl = async () => {
		const templateParam = route.query.template;
		if (!templateParam || typeof templateParam !== "string") return;
		if (!isValidParameter(templateParam)) {
			console.warn(`[useTemplateUrlLoader] Invalid template parameter format: ${templateParam}`);
			return;
		}
		const sourceParam = route.query.source || "default";
		if (!isValidParameter(sourceParam)) {
			console.warn(`[useTemplateUrlLoader] Invalid source parameter format: ${sourceParam}`);
			return;
		}
		const modeParam = route.query.mode;
		if (modeParam && (typeof modeParam !== "string" || !isValidParameter(modeParam))) {
			console.warn(`[useTemplateUrlLoader] Invalid mode parameter format: ${modeParam}`);
			return;
		}
		if (modeParam && !isSupportedMode(modeParam)) console.warn(`[useTemplateUrlLoader] Unsupported mode parameter: ${modeParam}. Supported modes: ${SUPPORTED_MODES.join(", ")}`);
		try {
			await templateWorkflows.loadTemplates();
			if (!await templateWorkflows.loadWorkflowTemplate(templateParam, sourceParam)) toast.add({
				severity: "error",
				summary: t("g.error"),
				detail: t("templateWorkflows.error.templateNotFound", { templateName: templateParam })
			});
			else if (modeParam === "linear") {
				useTelemetry()?.trackEnterLinear({ source: "template_url" });
				canvasStore.linearMode = true;
			}
		} catch (error) {
			console.error("[useTemplateUrlLoader] Failed to load template from URL:", error);
			toast.add({
				severity: "error",
				summary: t("g.error"),
				detail: t("g.errorLoadingTemplate")
			});
		} finally {
			cleanupUrlParams();
			clearPreservedQuery(TEMPLATE_NAMESPACE);
		}
	};
	return { loadTemplateFromUrl };
}
