//#region src/composables/useProgressFavicon.ts
var useProgressFavicon = () => {
	const defaultFavicon = "/assets/images/favicon_progress_16x16/frame_9.png";
	const favicon = useFavicon(defaultFavicon);
	const executionStore = useExecutionStore();
	const totalFrames = 10;
	watch([() => executionStore.executionProgress, () => executionStore.isIdle], ([progress, isIdle]) => {
		if (isIdle) favicon.value = defaultFavicon;
		else favicon.value = `/assets/images/favicon_progress_16x16/frame_${Math.min(Math.max(0, Math.floor(progress * totalFrames)), totalFrames - 1)}.png`;
	});
};
